import { PAYMENT_API_URL } from '../config';

export const createPaymentSession = async (orderId, amount, currency, description) => {
  const token = localStorage.getItem('token');
  const response = await fetch(`${PAYMENT_API_URL}/apple-pay/session`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    },
    body: JSON.stringify({ orderId, amount, currency, description })
  });
  return response.json();
};

export const processApplePayment = async (orderId, paymentToken) => {
  const token = localStorage.getItem('token');
  const response = await fetch(`${PAYMENT_API_URL}/apple-pay/process`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'Authorization': `Bearer ${token}`
    },
    body: JSON.stringify({ orderId, paymentToken })
  });
  return response.json();
};

export const getPaymentStatus = async (orderId) => {
  const token = localStorage.getItem('token');
  const response = await fetch(`${PAYMENT_API_URL}/status/${orderId}`, {
    method: 'GET',
    headers: {
      'Authorization': `Bearer ${token}`
    }
  });
  return response.json();
};

export const refundPayment = async (orderId) => {
  const token = localStorage.getItem('token');
  const response = await fetch(`${PAYMENT_API_URL}/refund/${orderId}`, {
    method: 'POST',
    headers: {
      'Authorization': `Bearer ${token}`
    }
  });
  return response.json();
};
